def findStrobogrammatic(n):
    def helper(n, final_len):
        if n == 0: return [""]
        if n == 1: return ["0", "1", "8"]
        res = []
        prev = helper(n - 2, final_len)
        for p in prev:
            if n != final_len: res.append("0" + p + "0")
            res.append("1" + p + "1")
            res.append("6" + p + "9")
            res.append("8" + p + "8")
            res.append("9" + p + "6")
        return res
    return helper(n, n)

